import sysfrom pathlib import Pathimport jsonimport reimport pandas as pdfrom gensim.models import Word2Vec# Ensure project root is on sys.pathPROJECT_ROOT = Path(__file__).resolve().parents[1]if str(PROJECT_ROOT) not in sys.path:    sys.path.insert(0, str(PROJECT_ROOT))from config import PROCESSED_DATA_DIR, EMBEDDINGS_DIR, REPORTS_DIRTEXT_COL = "full_text"MIN_TOKEN_LEN = 2def simple_tokenize(text: str):    """    Basic tokenizer:    - lowercase    - keep only alphabetic tokens / alphanumeric tokens    - drop very short tokens    """    text = str(text).lower()    tokens = re.findall(r"[a-zA-Z0-9]+", text)    tokens = [tok for tok in tokens if len(tok) >= MIN_TOKEN_LEN]    return tokensdef load_train_data():    train_df = pd.read_parquet(PROCESSED_DATA_DIR / "train_doc_5d.parquet")    return train_dfdef prepare_sentences(train_df: pd.DataFrame):    """    Convert each document into a token list for Word2Vec training.    """    tokenized_docs = train_df[TEXT_COL].astype(str).apply(simple_tokenize).tolist()    # Remove any empty docs just in case    tokenized_docs = [doc for doc in tokenized_docs if len(doc) > 0]    return tokenized_docsdef train_word2vec_model(tokenized_docs):    """    Train a Word2Vec model on document token lists.    """    model = Word2Vec(        sentences=tokenized_docs,        vector_size=100,        window=5,        min_count=2,        workers=4,        sg=1,          # skip-gram        epochs=10,        seed=42,    )    return modeldef save_outputs(model, tokenized_docs):    EMBEDDINGS_DIR.mkdir(parents=True, exist_ok=True)    REPORTS_DIR.mkdir(parents=True, exist_ok=True)    model_path = EMBEDDINGS_DIR / "word2vec_small_full.model"    vectors_path = EMBEDDINGS_DIR / "word2vec_small_full.kv"    report_path = REPORTS_DIR / "word2vec_training_summary.json"    model.save(str(model_path))    model.wv.save(str(vectors_path))    vocab_size = len(model.wv.key_to_index)    avg_doc_len = sum(len(doc) for doc in tokenized_docs) / len(tokenized_docs)    summary = {        "training_source": "train_doc_5d.parquet",        "n_documents": len(tokenized_docs),        "vocab_size": vocab_size,        "avg_document_length_tokens": avg_doc_len,        "vector_size": model.vector_size,        "window": model.window,        "min_count": model.min_count,        "sg": model.sg,        "epochs": model.epochs,    }    with open(report_path, "w", encoding="utf-8") as f:        json.dump(summary, f, indent=2)    print("\nSaved outputs:")    print(model_path)    print(vectors_path)    print(report_path)def main():    print("Loading document-level training data...")    train_df = load_train_data()    print("\nTrain dataframe shape:")    print(train_df.shape)    print("\nPreparing tokenized documents...")    tokenized_docs = prepare_sentences(train_df)    print(f"Number of tokenized documents: {len(tokenized_docs)}")    print(f"Sample tokenized document (first 30 tokens):\n{tokenized_docs[0][:30]}")    print("\nTraining Word2Vec model...")    model = train_word2vec_model(tokenized_docs)    print("\nTraining completed.")    print(f"Vocabulary size: {len(model.wv.key_to_index)}")    # Show a few sample nearest neighbors if available    sample_words = ["business", "risk", "market", "company"]    print("\nSample nearest neighbors:")    for word in sample_words:        if word in model.wv:            print(f"\n{word}:")            print(model.wv.most_similar(word, topn=5))        else:            print(f"\n{word}: not in vocabulary")    save_outputs(model, tokenized_docs)    print("\nDone.")if __name__ == "__main__":    main()